import React from 'react';
import ProgressBar from '../components/ProgressBar';
import './Dashboard.css';

const getDayKey = () => new Date().toISOString().split('T')[0];

export default function Dashboard({ sessions, nutrition }) {
  const today = nutrition[getDayKey()] || {};
  const totalSets = sessions.reduce((acc, s) => acc + s.exercises.reduce((a, e) => a + (e.sets?.length || 0), 0), 0);

  const stats = [
    { label: 'Séances créées', value: sessions.length, color: 'var(--accent)' },
    { label: 'Séries totales', value: totalSets, color: 'var(--purple)' },
    { label: 'Calories aujourd\'hui', value: today.calories || 0, color: 'var(--amber)' },
    { label: 'Protéines (g)', value: today.protein || 0, color: 'var(--green)' },
  ];

  return (
    <div className="dashboard">
      <h1 className="page-title">Tableau de bord ⚡</h1>

      <div className="stats-grid">
        {stats.map(s => (
          <div key={s.label} className="stat-card">
            <p className="stat-label">{s.label}</p>
            <p className="stat-value" style={{ color: s.color }}>{s.value}</p>
          </div>
        ))}
      </div>

      {today.calories > 0 && (
        <div className="dash-card">
          <h3>Nutrition du jour</h3>
          <div className="macro-row">
            <span>Calories</span>
            <span>{today.calories} / {today.caloriesGoal || 2500} kcal</span>
          </div>
          <ProgressBar value={today.calories} goal={today.caloriesGoal || 2500} color="var(--amber)" />

          <div className="macro-row" style={{ marginTop: 16 }}>
            <span>Protéines</span>
            <span>{today.protein}g / {today.proteinGoal || 150}g</span>
          </div>
          <ProgressBar value={today.protein} goal={today.proteinGoal || 150} color="var(--green)" />
        </div>
      )}

      {sessions.length === 0 && (
        <div className="empty-hint">
          <p>💡 Crée ta première séance dans <strong>Entraînement</strong></p>
        </div>
      )}
    </div>
  );
}
